@page "/catalog"
@using sv_6a369bd1f8314fe184f2540caf24323c.Services
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="d-flex catalog-container">
    @* Sidebar *@
    <aside class="catalog-sidebar">
        <CatalogFilters Categories="_categories"
                        OnApplyFilters="HandleApplyFilters"
                        OnClearFilters="HandleClearFilters" />
    </aside>

    @* Main Content *@
    <main class="catalog-main flex-grow-1">
        @if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_error is not null)
        {
            <div class="alert alert-danger m-3" role="alert">
                <strong>Error:</strong> @_error
                <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadProductsAsync">
                    Retry
                </button>
            </div>
        }
        else
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center p-3 border-bottom">
                <div>
                    <label class="form-label mb-0 me-2 fw-bold" for="sort-select">Sort by:</label>
                    <select id="sort-select"
                            class="form-select form-select-sm d-inline-block w-auto"
                            @bind="_sortBy"
                            @bind:after="HandleSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted">
                    @if (_result is { TotalCount: > 0 })
                    {
                        var first = (_result.Page - 1) * _result.PageSize + 1;
                        var last = Math.Min(_result.Page * _result.PageSize, _result.TotalCount);
                        @($"Showing {first}\u2013{last} of {_result.TotalCount} products")
                    }
                </span>
            </div>

            @if (_result is null or { Items.Count: 0 })
            {
                <div class="text-center py-5 text-muted">
                    <h4>No products found</h4>
                    <p>Try adjusting your filters.</p>
                </div>
            }
            else
            {
                @* Product Grid *@
                <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3 p-3">
                    @foreach (var product in _result.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnSelected="@(() => OnProductSelected.InvokeAsync(product))"
                                         OnAddToCart="@(() => HandleAddToCart(product))" />
                        </div>
                    }
                </div>

                @* Pagination *@
                <CatalogPagination CurrentPage="_currentPage"
                                   TotalPages="TotalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        }
    </main>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? _categories;
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;
    private bool _loading = true;
    private string? _error;

    private int TotalPages =>
        _result is { TotalCount: > 0 }
            ? (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize)
            : 1;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
            await LoadProductsAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task LoadProductsAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            StateHasChanged();

            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleSortChanged()
    {
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandleClearFilters()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProductsAsync();
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart functionality
        return Task.CompletedTask;
    }
}

.catalog-container {
    min-height: calc(100vh - 60px);
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    border-right: 1px solid #dee2e6;
    background-color: #f8f9fa;
    flex-shrink: 0;
}

.catalog-main {
    width: 75%;
}

